/**
 * @system — OAuthButtons
 *
 * Renders "Sign in with Google" and "Sign in with GitHub" buttons.
 * Clicking a button triggers a full-page redirect to the backend OAuth
 * initiation endpoint (/api/auth/google or /api/auth/github), which then
 * redirects the user to the provider consent page.
 *
 * Buttons are only rendered when the corresponding env var is detected via
 * the VITE_OAUTH_PROVIDERS flag, or are always shown and gracefully handled
 * by the server returning 501 if not configured.
 */

import { Github } from 'lucide-react'
import { Button } from '../ui/button'

// Google uses official brand colors not available in lucide-react
function GoogleIcon() {
  return (
    <svg viewBox="0 0 24 24" width="16" height="16" aria-hidden="true">
      <path
        fill="#4285F4"
        d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
      />
      <path
        fill="#34A853"
        d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
      />
      <path
        fill="#FBBC05"
        d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"
      />
      <path
        fill="#EA4335"
        d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
      />
    </svg>
  )
}

const API_BASE = import.meta.env.VITE_API_URL ?? '/api'


export function OAuthButtons({ className = '' }) {
  function initiateOAuth(provider) {
    window.location.href = `${API_BASE}/auth/${provider}`
  }

  return (
    <div className={`space-y-2 ${className}`}>
      <div className="relative flex items-center py-2">
        <div className="flex-1 border-t border-border" />
        <span className="mx-3 text-xs text-muted-foreground">or continue with</span>
        <div className="flex-1 border-t border-border" />
      </div>

      <div className="grid grid-cols-2 gap-2">
        <Button
          type="button"
          variant="outline"
          className="w-full gap-2"
          onClick={() => initiateOAuth('google')}
        >
          <GoogleIcon />
          Google
        </Button>

        <Button
          type="button"
          variant="outline"
          className="w-full gap-2"
          onClick={() => initiateOAuth('github')}
        >
          <Github className="h-4 w-4" aria-hidden="true" />
          GitHub
        </Button>
      </div>
    </div>
  )
}
